// server/middleware.ts
import { eq as eq3 } from "drizzle-orm";
import bcrypt from "bcryptjs";
async function isAdmin2(req, res, next) {
  try {
    const adminId = req.session?.adminId;
    if (process.env.DEBUG_AUTH === "1") {
      console.log("[isAdmin] path", req.path, "adminId", adminId);
    }
    if (adminId) {
      const [admin2] = await withRetry(
        () => db.select().from(admins).where(eq3(admins.id, adminId)).limit(1)
      );
      if (admin2) {
        req.admin = admin2;
        return next();
      }
    }
    let userEmail = req.user?.claims?.email || req.user?.email;
    if (!userEmail) {
      const authHeader = req.headers.authorization;
      if (authHeader && authHeader.startsWith("Bearer ")) {
        const token = authHeader.substring(7);
        try {
          const { data: { user }, error } = await supabase.auth.getUser(token);
          if (!error && user?.email) {
            userEmail = user.email;
          }
        } catch (e) {
        }
      }
    }
    if (!userEmail) {
      return res.status(401).json({ message: "Unauthorized" });
    }
    const [admin] = await withRetry(
      () => db.select().from(admins).where(eq3(admins.email, userEmail)).limit(1)
    );
    if (!admin) {
      return res.status(403).json({ message: "Forbidden - Admin access required" });
    }
    req.admin = admin;
    if (req.session && !req.session.adminId) {
      req.session.adminId = admin.id;
    }
    next();
  } catch (error) {
    console.error("Error checking admin status:", error);
    return res.status(500).json({ message: "Internal server error" });
  }
}

