import { z } from "zod";
import { eq as eq4 } from "drizzle-orm";
function registerNotapayersRoutes(app) {
  app.get("/api/admin/notapayers/followup-config", isAdmin2, async (req, res) => {
    try {
      const config = await storage.getNotapayerFollowupConfig();
      res.json({
        success: true,
        config: config || {
          isEnabled: false,
          activeDays: 3,
          // Dias após expiração
          maxAttempts: 3,
          messageTemplate: "Ol\xE1! Seu plano expirou. Quer renovar?",
          tone: "friendly",
          useEmojis: true,
          activeDaysStart: 1,
          activeDaysEnd: 7
        }
      });
    } catch (error) {
      console.error("Erro ao buscar configura\xE7\xE3o:", error);
      res.status(500).json({ success: false, message: "Erro ao buscar configura\xE7\xE3o" });
    }
  });
  app.put("/api/admin/notapayers/followup-config", isAdmin2, async (req, res) => {
    try {
      const schema = z.object({
        isEnabled: z.boolean().optional(),
        activeDays: z.number().optional(),
        maxAttempts: z.number().optional(),
        messageTemplate: z.string().optional(),
        tone: z.enum(["friendly", "professional", "urgent"]).optional(),
        useEmojis: z.boolean().optional(),
        activeDaysStart: z.number().optional(),
        activeDaysEnd: z.number().optional()
      });
      const parsed = schema.safeParse(req.body);
      if (!parsed.success) {
        return res.status(400).json({
          success: false,
          message: "Dados inv\xE1lidos",
          errors: parsed.error.errors
        });
      }
      const config = await storage.updateNotapayerFollowupConfig(parsed.data);
      res.json({
        success: true,
        config,
        message: "Configura\xE7\xE3o atualizada com sucesso"
      });
    } catch (error) {
      console.error("Erro ao atualizar configura\xE7\xE3o:", error);
      res.status(500).json({ success: false, message: "Erro ao atualizar configura\xE7\xE3o" });
    }
  });
  app.get("/api/admin/notapayers/list", isAdmin2, async (req, res) => {
    try {
      const config = await storage.getNotapayerFollowupConfig();
      if (!config || !config.isEnabled) {
        return res.json({
          success: true,
          data: [],
          message: "Follow-up para n\xE3o pagantes est\xE1 desativado"
        });
      }
      const now = /* @__PURE__ */ new Date();
      const activeDaysStart = config.activeDaysStart || 1;
      const activeDaysEnd = config.activeDaysEnd || 7;
      const inactiveSubscriptions = await db.query.subscriptions.findMany({
        where: (subs, { and: and11, lte: lte4, or: or4, eq: eq16 }) => and11(
          or4(eq16(subs.status, "expired"), eq16(subs.status, "cancelled")),
          lte4(subs.dataFim, now)
        ),
        with: {
          user: true,
          plan: true
        }
      });
      const eligibleSubscriptions = inactiveSubscriptions.filter((sub) => {
        const dataFim = sub.dataFim ? new Date(sub.dataFim) : null;
        if (!dataFim) return false;
        const daysSinceExpiry = (now.getTime() - dataFim.getTime()) / (1e3 * 60 * 60 * 24);
        return daysSinceExpiry >= activeDaysStart && daysSinceExpiry <= activeDaysEnd;
      });
      const listWithAttempts = await Promise.all(
        eligibleSubscriptions.map(async (sub) => {
          const attempts = await storage.getNotapayerFollowupAttempts(sub.userId);
          const dataFim = sub.dataFim ? new Date(sub.dataFim) : null;
          return {
            id: sub.id,
            userId: sub.userId,
            userName: sub.user?.name || sub.user?.nome || "Desconhecido",
            userEmail: sub.user?.email || "",
            phone: sub.user?.whatsappNumber || "",
            planName: sub.plan?.nome || "Plano",
            planPrice: sub.plan?.valor || "0",
            expiresAt: sub.dataFim,
            daysSinceExpiry: dataFim ? Math.floor((now.getTime() - dataFim.getTime()) / (1e3 * 60 * 60 * 24)) : 0,
            attempts: attempts.length,
            lastAttempt: attempts[attempts.length - 1] || null
          };
        })
      );
      res.json({
        success: true,
        data: listWithAttempts,
        total: listWithAttempts.length
      });
    } catch (error) {
      console.error("Erro ao listar n\xE3o pagantes:", error);
      res.status(500).json({ success: false, message: "Erro ao listar n\xE3o pagantes" });
    }
  });
  app.post("/api/admin/notapayers/send-followup/:userId", isAdmin2, async (req, res) => {
    try {
      const { userId } = req.params;
      const user = await storage.getUser(userId);
      if (!user) {
        return res.status(404).json({ success: false, message: "Usu\xE1rio n\xE3o encontrado" });
      }
      const inactiveSub = await db.query.subscriptions.findFirst({
        where: (subs, { and: and11, lte: lte4, or: or4, eq: eq16 }) => and11(
          eq16(subs.userId, userId),
          or4(eq16(subs.status, "expired"), eq16(subs.status, "cancelled")),
          lte4(subs.dataFim, /* @__PURE__ */ new Date())
        )
      });
      if (!inactiveSub) {
        return res.status(404).json({
          success: false,
          message: "Usu\xE1rio n\xE3o tem assinatura inativa"
        });
      }
      const config = await storage.getNotapayerFollowupConfig();
      if (!config) {
        return res.status(500).json({
          success: false,
          message: "Configura\xE7\xE3o de follow-up n\xE3o encontrada"
        });
      }
      const message = config.messageTemplate.replace(/{userName}/g, user.name || "cliente");
      const connection = await storage.getConnectionByUserId(userId);
      if (!connection) {
        return res.status(404).json({
          success: false,
          message: "WhatsApp n\xE3o conectado para este usu\xE1rio"
        });
      }
      console.log(`[NOTAPAYER-FOLLOWUP] Enviando para ${user.whatsappNumber}: ${message}`);
      await storage.createNotapayerFollowupAttempt({
        userId,
        subscriptionId: inactiveSub.id,
        message,
        sentAt: /* @__PURE__ */ new Date(),
        status: "sent"
      });
      res.json({
        success: true,
        message: "Follow-up enviado com sucesso",
        user: {
          id: user.id,
          name: user.name,
          phone: user.whatsappNumber
        },
        sentMessage: message
      });
    } catch (error) {
      console.error("Erro ao enviar follow-up:", error);
      res.status(500).json({ success: false, message: "Erro ao enviar follow-up" });
    }
  });
  app.get("/api/admin/notapayers/history", isAdmin2, async (req, res) => {
    try {
      const limit = parseInt(req.query.limit) || 100;
      const attempts = await storage.getNotapayerFollowupHistory(limit);
      res.json({
        success: true,
        data: attempts,
        total: attempts.length
      });
    } catch (error) {
      console.error("Erro ao buscar hist\xF3rico:", error);
      res.status(500).json({ success: false, message: "Erro ao buscar hist\xF3rico" });
    }
  });
  app.post("/api/admin/notapayers/resubscribe/:userId", isAdmin2, async (req, res) => {
    try {
      const { userId } = req.params;
      const user = await storage.getUser(userId);
      if (!user) {
        return res.status(404).json({ success: false, message: "Usu\xE1rio n\xE3o encontrado" });
      }
      const inactiveSub = await db.query.subscriptions.findFirst({
        where: (subs, { and: and11, lte: lte4, or: or4, eq: eq16 }) => and11(
          eq16(subs.userId, userId),
          or4(eq16(subs.status, "expired"), eq16(subs.status, "cancelled")),
          lte4(subs.dataFim, /* @__PURE__ */ new Date())
        )
      });
      if (!inactiveSub) {
        return res.status(404).json({
          success: false,
          message: "Usu\xE1rio n\xE3o tem assinatura inativa"
        });
      }
      const updatedSub = await db.update(subscriptions).set({
        status: "active",
        dataFim: new Date(Date.now() + 30 * 24 * 60 * 60 * 1e3)
        // +30 dias
      }).where(eq4(subscriptions.id, inactiveSub.id)).returning();
      res.json({
        success: true,
        message: "Assinatura reativada com sucesso",
        subscription: updatedSub[0]
      });
    } catch (error) {
      console.error("Erro ao reativar assinatura:", error);
      res.status(500).json({ success: false, message: "Erro ao reativar assinatura" });
    }
  });
  console.log("\u2705 [NOTAPAYERS] Rotas de follow-up para n\xE3o pagantes registradas");
}

