function buildWhatsAppUrl(phoneNumber, message) {
  const digits = phoneNumber.replace(/\D/g, "");
  if (!message) {
    return `https://wa.me/${digits}`;
  }
  const encoded = encodeURIComponent(message);
  return `https://wa.me/${digits}?text=${encoded}`;
}
