import path from "path";
import crypto from "crypto";
var BUCKET = process.env.SUPABASE_TICKET_ATTACHMENTS_BUCKET || "ticket-attachments";
async function uploadImageBuffer(buffer, originalName, mimeType) {
  const sha256 = crypto.createHash("sha256").update(buffer).digest("hex");
  const ext = path.extname(originalName) || ".png";
  const key = `tickets/${Date.now()}-${crypto.randomBytes(8).toString("hex")}${ext}`;
  const { error } = await supabase.storage.from(BUCKET).upload(key, buffer, {
    contentType: mimeType,
    upsert: false,
    cacheControl: "3600"
  });
  if (error) throw new Error(`Supabase Storage upload failed: ${error.message}`);
  const { data: urlData } = supabase.storage.from(BUCKET).getPublicUrl(key);
  return {
    provider: "supabase",
    key,
    url: urlData.publicUrl,
    sha256
  };
}
