function formatContextForAgent(products, businessInfo, websiteUrl) {
  let context = `

## \u{1F4E6} CAT\xC1LOGO DE PRODUTOS/SERVI\xC7OS (Importado de: ${websiteUrl})
`;
  if (businessInfo.businessName) {
    context += `
### Sobre o Neg\xF3cio
`;
    if (businessInfo.businessName) context += `- **Nome:** ${businessInfo.businessName}
`;
    if (businessInfo.businessDescription) context += `- **Descri\xE7\xE3o:** ${businessInfo.businessDescription}
`;
    if (businessInfo.contactPhone) context += `- **Telefone:** ${businessInfo.contactPhone}
`;
    if (businessInfo.contactEmail) context += `- **Email:** ${businessInfo.contactEmail}
`;
    if (businessInfo.address) context += `- **Endere\xE7o:** ${businessInfo.address}
`;
    if (businessInfo.workingHours) context += `- **Hor\xE1rio:** ${businessInfo.workingHours}
`;
    if (businessInfo.socialMedia && Object.keys(businessInfo.socialMedia).length > 0) {
      context += `- **Redes Sociais:**
`;
      for (const [name, url] of Object.entries(businessInfo.socialMedia)) {
        context += `  - ${name}: ${url}
`;
      }
    }
  }
  if (products.length > 0) {
    context += `
### Produtos/Servi\xE7os Dispon\xEDveis (${products.length} itens)
`;
    for (const product of products) {
      context += `
**${product.name}**
`;
      if (product.price) context += `- Pre\xE7o: ${product.price}
`;
      if (product.description) context += `- ${product.description}
`;
      if (product.category) context += `- Categoria: ${product.category}
`;
      if (product.availability) context += `- Disponibilidade: ${product.availability}
`;
    }
  }
  context += `
---
`;
  context += `*Dados atualizados automaticamente via importa\xE7\xE3o de website.*
`;
  return context;
}
async function scrapeWebsite(url, retryCount = 0) {
  const startTime = Date.now();
  const validation = validateUrl(url);
  if (!validation.valid) {
    return {
      success: false,
      websiteUrl: url,
      extractedText: "",
      products: [],
      businessInfo: {},
      formattedContext: "",
      pagesScraped: 0,
      productsFound: 0,
      error: validation.error
    };
  }
  const normalizedUrl = validation.normalizedUrl;
  console.log(`[WebsiteScraper] Iniciando scraping de: ${normalizedUrl}`);
  let page = null;
  try {
    const browserInstance = await getBrowser();
    page = await browserInstance.newPage();
    await page.setViewportSize({ width: 1920, height: 1080 });
    await page.setExtraHTTPHeaders({
      "User-Agent": SCRAPER_CONFIG.userAgent,
      "Accept-Language": "pt-BR,pt;q=0.9,en-US;q=0.8,en;q=0.7"
    });
    await page.goto(normalizedUrl, {
      waitUntil: "domcontentloaded",
      timeout: SCRAPER_CONFIG.timeout
    });
    await page.waitForTimeout(2e3);
    const extractedText = await extractTextFromPage(page);
    console.log(`[WebsiteScraper] Texto extra\xEDdo: ${extractedText.length} chars`);
    const extractedHtml = await page.content();
    const limitedHtml = extractedHtml.slice(0, SCRAPER_CONFIG.maxHtmlLength);
    let products = await extractJsonLdProducts(page);
    console.log(`[WebsiteScraper] Produtos JSON-LD encontrados: ${products.length}`);
    if (products.length === 0) {
      products = await extractProductsBySelectors(page);
      console.log(`[WebsiteScraper] Produtos por seletores: ${products.length}`);
    }
    if (products.length === 0 && extractedText.length > 100) {
      console.log(`[WebsiteScraper] Usando Mistral para extrair produtos...`);
      products = await extractProductsWithMistral(extractedText);
      console.log(`[WebsiteScraper] Produtos via Mistral: ${products.length}`);
    }
    const businessInfo = await extractBusinessInfo(page, extractedText);
    const formattedContext = formatContextForAgent(products, businessInfo, normalizedUrl);
    const elapsed = Date.now() - startTime;
    console.log(`[WebsiteScraper] Scraping completo em ${elapsed}ms`);
    return {
      success: true,
      websiteUrl: normalizedUrl,
      websiteName: businessInfo.businessName,
      websiteDescription: businessInfo.businessDescription,
      extractedText,
      extractedHtml: limitedHtml,
      products,
      businessInfo,
      formattedContext,
      pagesScraped: 1,
      productsFound: products.length
    };
  } catch (error) {
    console.error(`[WebsiteScraper] Erro:`, error.message);
    if (retryCount < SCRAPER_CONFIG.maxRetries - 1) {
      console.log(`[WebsiteScraper] Tentativa ${retryCount + 2}/${SCRAPER_CONFIG.maxRetries}...`);
      await new Promise((r) => setTimeout(r, 2e3 * (retryCount + 1)));
      return scrapeWebsite(url, retryCount + 1);
    }
    return {
      success: false,
      websiteUrl: url,
      extractedText: "",
      products: [],
      businessInfo: {},
      formattedContext: "",
      pagesScraped: 0,
      productsFound: 0,
      error: `Falha ao acessar o site: ${error.message}`
    };
  } finally {
    if (page) {
      await page.close().catch(() => {
      });
    }
  }
}
process.on("beforeExit", async () => {
  await closeBrowser();
});

