  app.post("/api/admin/users/bulk-delete", isAdmin2, async (req, res) => {
    const { userIds } = req.body;
    if (!userIds || !Array.isArray(userIds) || userIds.length === 0) {
      return res.status(400).json({ message: "No user IDs provided" });
    }
    try {
      let deletedCount = 0;
      let skippedCount = 0;
      const errors = [];
      for (const userId of userIds) {
        try {
          const user = await storage.getUser(userId);
          if (!user) {
            errors.push(`User ${userId} not found`);
            continue;
          }
          if (user.role === "admin" || user.role === "owner") {
            skippedCount++;
            console.log(`[ADMIN BULK DELETE] Skipped admin/owner: ${user.email}`);
            continue;
          }
          const activeSubscription = await storage.getUserSubscription(userId);
          if (activeSubscription && activeSubscription.status === "active") {
            skippedCount++;
            console.log(`[ADMIN BULK DELETE] Skipped user with active plan: ${user.email}`);
            continue;
          }
          await storage.deleteUser(userId);
          deletedCount++;
          console.log(`[ADMIN BULK DELETE] Deleted user ${userId} (${user.email})`);
        } catch (error) {
          errors.push(`Failed to delete user ${userId}`);
          console.error(`[ADMIN BULK DELETE] Error deleting user ${userId}:`, error);
        }
      }
      res.json({
        success: true,
        deletedCount,
        skippedCount,
        message: `${deletedCount} usu\xC3\xA1rio(s) exclu\xC3\xADdo(s)${skippedCount > 0 ? `, ${skippedCount} ignorado(s) (admins ou com plano ativo)` : ""}${errors.length > 0 ? `. ${errors.length} erro(s).` : ""}`
      });
    } catch (error) {
      console.error("Error in bulk delete:", error);
      res.status(500).json({ message: "Error deleting users" });
    }
  });
