  app.post("/api/exclusion/list/bulk", isAuthenticated, async (req, res) => {
    try {
      const userId = getUserId6(req);
      const { numbers, excludeFromFollowup } = req.body;
      if (!numbers || !Array.isArray(numbers) || numbers.length === 0) {
        return res.status(400).json({ message: "Array de n\xC3\xBAmeros \xC3\xA9 obrigat\xC3\xB3rio" });
      }
      const cleanNumbers = numbers.map((n) => n.replace(/\D/g, "").trim()).filter((n) => n.length >= 8 && n.length <= 15);
      if (cleanNumbers.length === 0) {
        return res.status(400).json({ message: "Nenhum n\xC3\xBAmero v\xC3\xA1lido encontrado" });
      }
      const existingList = await storage.getExclusionList(userId);
      const existingNumbers = new Set(existingList.map((item) => item.phoneNumber));
      const newNumbers = cleanNumbers.filter((n) => !existingNumbers.has(n));
      let added = 0;
      let skipped = cleanNumbers.length - newNumbers.length;
      for (const phoneNumber of newNumbers) {
        try {
          await storage.addToExclusionList({
            userId,
            phoneNumber,
            contactName: null,
            reason: null,
            excludeFromFollowup: excludeFromFollowup ?? true,
            isActive: true
          });
          added++;
        } catch (err) {
          skipped++;
        }
      }
      console.log(`?? [EXCLUSION BULK] ${added} n\xC3\xBAmeros adicionados, ${skipped} ignorados (usu\xC3\xA1rio ${userId})`);
      res.json({
        added,
        skipped,
        total: cleanNumbers.length,
        message: `${added} n\xC3\xBAmeros bloqueados com sucesso`
      });
    } catch (error) {
      console.error("Error bulk adding to exclusion list:", error);
      res.status(500).json({ message: "Falha ao adicionar n\xC3\xBAmeros" });
    }
  });
