// server/autoReactivateService.ts
var CHECK_INTERVAL_FAST_MS = 30 * 1e3;
var CHECK_INTERVAL_SLOW_MS = 5 * 60 * 1e3;
var CHECK_INTERVAL_IDLE_MS = 10 * 60 * 1e3;
var checkInterval = null;
var isRunning2 = false;
var currentIntervalMs = CHECK_INTERVAL_SLOW_MS;
var consecutiveEmptyChecks = 0;
var lastActiveTimerCount = 0;
function startAutoReactivationService() {
  if (checkInterval) {
    console.log(`\u23F0 [AUTO-REACTIVATE] Servi\xE7o j\xE1 est\xE1 rodando`);
    return;
  }
  console.log(`\u23F0 [AUTO-REACTIVATE] Iniciando servi\xE7o otimizado (intervalo inicial: ${currentIntervalMs / 1e3}s)`);
  scheduleNextCheck();
  setTimeout(async () => {
    if (!isRunning2) {
      await runCheck();
    }
  }, 5e3);
}
function scheduleNextCheck() {
  if (checkInterval) {
    clearTimeout(checkInterval);
  }
  checkInterval = setTimeout(async () => {
    await runCheck();
    scheduleNextCheck();
  }, currentIntervalMs);
}
async function runCheck() {
  if (isRunning2) {
    console.log(`\u23F0 [AUTO-REACTIVATE] Verifica\xE7\xE3o anterior ainda em execu\xE7\xE3o, pulando...`);
    return;
  }
  isRunning2 = true;
  try {
    await checkAndReactivateConversations();
  } catch (error) {
    console.error(`\u274C [AUTO-REACTIVATE] Erro na verifica\xE7\xE3o:`, error);
  } finally {
    isRunning2 = false;
  }
}
async function adjustPollingInterval() {
  try {
    const activeTimers = await storage.countActiveAutoReactivateTimers();
    lastActiveTimerCount = activeTimers;
    let newInterval;
    let reason;
    if (activeTimers === 0) {
      newInterval = CHECK_INTERVAL_IDLE_MS;
      reason = "nenhum timer ativo";
      consecutiveEmptyChecks = 0;
    } else if (consecutiveEmptyChecks >= 10) {
      newInterval = CHECK_INTERVAL_SLOW_MS;
      reason = `${consecutiveEmptyChecks} checks vazios consecutivos`;
    } else {
      newInterval = CHECK_INTERVAL_FAST_MS;
      reason = `${activeTimers} timers ativos`;
    }
    if (newInterval !== currentIntervalMs) {
      console.log(`\u23F0 [AUTO-REACTIVATE] Intervalo ajustado: ${currentIntervalMs / 1e3}s \u2192 ${newInterval / 1e3}s (${reason})`);
      currentIntervalMs = newInterval;
    }
  } catch (error) {
    console.error(`\u274C [AUTO-REACTIVATE] Erro ao ajustar intervalo:`, error);
  }
}
async function checkAndReactivateConversations() {
  try {
    const hasPending = await storage.hasConversationsToAutoReactivate();
    if (!hasPending) {
      consecutiveEmptyChecks++;
      await adjustPollingInterval();
      return;
    }
    consecutiveEmptyChecks = 0;
    const conversationsToReactivate = await storage.getConversationsToAutoReactivate();
    if (conversationsToReactivate.length === 0) {
      await adjustPollingInterval();
      return;
    }
    console.log(`\u23F0 [AUTO-REACTIVATE] Processando ${conversationsToReactivate.length} conversas`);
    for (const conv of conversationsToReactivate) {
      try {
        const conversation = await storage.getConversation(conv.conversationId);
        if (!conversation) {
          console.log(`\u26A0\uFE0F [AUTO-REACTIVATE] Conversa ${conv.conversationId} n\xE3o encontrada, removendo...`);
          await storage.enableAgentForConversation(conv.conversationId);
          continue;
        }
        const connection = await storage.getConnectionById(conversation.connectionId);
        if (!connection) {
          console.log(`\u26A0\uFE0F [AUTO-REACTIVATE] Conex\xE3o n\xE3o encontrada para conversa ${conv.conversationId}`);
          await storage.enableAgentForConversation(conv.conversationId);
          continue;
        }
        const businessAgentConfig = await storage.getBusinessAgentConfig(connection.userId);
        if (!businessAgentConfig?.isActive) {
          console.log(`\u{1F6AB} [AUTO-REACTIVATE] IA desativada GLOBALMENTE para user ${connection.userId} - N\xC3O reativando conversa ${conv.conversationId}`);
          continue;
        }
        const agentConfig = await storage.getAgentConfig(connection.userId);
        if (!agentConfig?.isActive) {
          console.log(`\u{1F6AB} [AUTO-REACTIVATE] Agente IA desativado em ai_agent_config para user ${connection.userId} - N\xC3O reativando`);
          continue;
        }
        console.log(`\u{1F504} [AUTO-REACTIVATE] Reativando IA para conversa ${conv.conversationId} (${conversation.contactName || conversation.contactNumber})`);
        await storage.enableAgentForConversation(conv.conversationId);
        broadcastToUser(connection.userId, {
          type: "agent_auto_reactivated",
          conversationId: conv.conversationId,
          reason: "timer_expired",
          hasPendingMessage: conv.clientHasPendingMessage ?? false
        });
        if (conv.clientHasPendingMessage) {
          try {
            const triggerResult = await triggerAgentResponseForConversation(connection.userId, conv.conversationId);
            console.log(`\u2705 [AUTO-REACTIVATE] IA reativada e respondendo para ${conv.conversationId}: ${triggerResult.reason}`);
          } catch (triggerError) {
            console.error(`\u274C [AUTO-REACTIVATE] Erro ao disparar resposta para ${conv.conversationId}:`, triggerError);
          }
        } else {
          console.log(`\u2705 [AUTO-REACTIVATE] IA reativada para ${conv.conversationId} (sem msg pendente - aguardando pr\xF3xima mensagem do cliente)`);
        }
      } catch (convError) {
        console.error(`\u274C [AUTO-REACTIVATE] Erro ao processar conversa ${conv.conversationId}:`, convError);
      }
    }
    await adjustPollingInterval();
  } catch (error) {
    console.error(`\u274C [AUTO-REACTIVATE] Erro ao buscar conversas:`, error);
  }
}

